
"use client"
import { useState, useEffect } from 'react'
import './styles/home.css'

export default function Home() {
  const [theme, setTheme] = useState('dark')
  const [menuOpen, setMenuOpen] = useState(false)
  const [scrolled, setScrolled] = useState(0)
  const [sending, setSending] = useState(false)
  const [formMsg, setFormMsg] = useState('')

  useEffect(() => {
    if (theme === 'light') {
      document.body.classList.add('light')
    } else {
      document.body.classList.remove('light')
    }
  }, [theme])

  useEffect(() => {
    const handleScroll = () => {
      const pct = (window.scrollY / (document.body.scrollHeight - window.innerHeight)) * 100
      setScrolled(Math.min(pct, 100))
    }
    window.addEventListener('scroll', handleScroll)
    return () => window.removeEventListener('scroll', handleScroll)
  }, [])

  const downloadCV = () => {
    const b64 = ""
    const binary = atob(b64)
    const bytes = new Uint8Array(binary.length)
    for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i)
    const blob = new Blob([bytes], { type: 'application/pdf' })
    const a = document.createElement('a')
    a.href = URL.createObjectURL(blob)
    a.download = 'Muhammad-Awais-Resume.pdf'
    a.click()
  }

  const handleContact = async (e) => {
    e.preventDefault()
    const form = e.target
    const name = form.name.value
    const email = form.email.value
    const subject = form.subject.value || 'Portfolio Contact'
    const message = form.message.value

    setSending(true)
    setFormMsg('')

    try {
      const res = await fetch('/api/contact', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ name, email, subject, message })
      })

      if (res.ok) {
        setFormMsg("✓ Message sent! I'll reply soon.")
        form.reset()
        setTimeout(() => setFormMsg(''), 4000)
      } else {
        const err = await res.json()
        setFormMsg('Error: ' + (err.error || 'Failed to send'))
      }
    } catch (err) {
      setFormMsg('Error: ' + err.message)
    } finally {
      setSending(false)
    }
  }

  return (
    <div className="portfolio">
      <div id="progress-bar" style={{ width: scrolled + '%' }}></div>
      <div className="color-strip"></div>

      <nav className="navbar">
        <a href="#" className="nav-logo">MA<span>.</span></a>
        <ul className="nav-links">
          <li><a href="#education">Education</a></li>
          <li><a href="#projects">Projects</a></li>
          <li><a href="#skills">Skills</a></li>
          <li><a href="#contact">Contact</a></li>
          <li><a href="https://linkedin.com/in/muhammad-awais-0287743a9" target="_blank" className="linkedin-btn">🔗 LinkedIn</a></li>
        </ul>
        <div className="nav-right">
          <button className="btn-cv" onClick={downloadCV}>⬇ CV</button>
          <button className="theme-btn" onClick={() => setTheme(theme === 'dark' ? 'light' : 'dark')}>
            {theme === 'dark' ? '☀ Light' : '☾ Dark'}
          </button>
          <button className="hamburger" onClick={() => setMenuOpen(!menuOpen)}>
            <span></span><span></span><span></span>
          </button>
        </div>
      </nav>

      {menuOpen && (
        <div className="mobile-menu">
          <a href="#education" onClick={() => setMenuOpen(false)}>Education</a>
          <a href="#projects" onClick={() => setMenuOpen(false)}>Projects</a>
          <a href="#skills" onClick={() => setMenuOpen(false)}>Skills</a>
          <a href="#contact" onClick={() => setMenuOpen(false)}>Contact</a>
          <a href="#hire" onClick={() => setMenuOpen(false)} className="mm-hire">Hire Me</a>
          <a href="https://linkedin.com/in/muhammad-awais-0287743a9" target="_blank">LinkedIn</a>
          <button onClick={() => { downloadCV(); setMenuOpen(false) }} style={{textAlign:'left'}}>⬇ Download CV</button>
        </div>
      )}

      <section className="hero" id="home">
        <div className="hero-left">
          <span className="hero-tag">CS Student &amp; Aspiring Developer</span>
          <h1 className="hero-name">Muhammad<br/><span className="line2">Awais.</span></h1>
          <div className="hero-title">Web Dev · AI Enthusiast · Problem Solver</div>
          <p className="hero-bio">Aspiring Computer Science student at Iqra University, Karachi — building smart, real-world applications with Python, HTML/CSS, JavaScript, and Bootstrap. Passionate about AI and modern tech.</p>
          <div className="hero-seeking"><span className="seek-dot"></span> Currently seeking first industry internship opportunity</div>
          <div className="hero-ctas">
            <a href="#projects" className="btn btn-primary">See My Work</a>
            <button onClick={downloadCV} className="btn btn-cv">Download CV</button>
            <a href="#hire" className="btn btn-outline">Hire Me</a>
          </div>
        </div>
        <div className="hero-right">
          <div className="hero-photo-wrap">
            <img src="data:image/png;base64," alt="Muhammad Awais" className="hero-photo" />
            <div className="hero-overlay"></div>
            <div className="hero-pills">
              <span className="pill pill-pink">Python</span>
              <span className="pill pill-cyan">JavaScript</span>
              <span className="pill pill-green">AI &amp; ML</span>
            </div>
          </div>
        </div>
      </section>

      <section id="education" className="section-light">
        <div className="section-header">
          <span className="section-tag">// background</span>
          <h2 className="section-title">Education</h2>
          <p className="section-sub">My academic journey building a strong foundation in Computer Science and engineering.</p>
        </div>
        <div className="edu-grid">
          <div className="edu-card">
            <div className="edu-icon uni">🎓</div>
            <div className="edu-body">
              <div className="edu-degree">BS Computer Science</div>
              <div className="edu-school">Iqra University, Karachi — Expected Graduation: 2027</div>
              <div className="edu-meta">
                <span className="edu-badge purple">In Progress</span>
                <span className="edu-badge yellow">Focus: Web Dev &amp; AI</span>
              </div>
            </div>
          </div>
          <div className="edu-card">
            <div className="edu-icon">📘</div>
            <div className="edu-body">
              <div className="edu-degree">Intermediate — Pre-Engineering</div>
              <div className="edu-school">Mehran Model School &amp; College — 2021–2023</div>
              <div className="edu-meta">
                <span className="edu-badge cyan">822 / 1100</span>
                <span className="edu-badge cyan">74.73%</span>
              </div>
            </div>
          </div>
        </div>
      </section>

      <section id="projects">
        <div className="section-header">
          <span className="section-tag">// my work</span>
          <h2 className="section-title">Projects</h2>
          <p className="section-sub">Academic and self-initiated projects built with modern technologies.</p>
        </div>
        <div className="projects-grid">
          <div className="proj-card web">
            <div className="proj-info">
              <div className="proj-cat">Web Development</div>
              <div className="proj-name">Carflex UK — Vehicle History Checker</div>
              <p className="proj-desc">Professional UK vehicle history checker. Users enter any registration plate to get instant access to detailed vehicle data.</p>
              <div className="proj-tags">
                <span className="tag">HTML5</span>
                <span className="tag">CSS3</span>
                <span className="tag">Bootstrap</span>
                <span className="tag">JavaScript</span>
              </div>
            </div>
            <a href="https://carlfex-uk.netlify.app/" target="_blank" className="btn-live">Live ↗</a>
          </div>

          <div className="proj-card ai">
            <div className="proj-info">
              <div className="proj-cat">Python</div>
              <div className="proj-name">Python CLI Applications</div>
              <p className="proj-desc">Multiple projects including grade calculator, file organizer, and to-do list manager demonstrating OOP principles.</p>
              <div className="proj-tags">
                <span className="tag">Python</span>
                <span className="tag">OOP</span>
                <span className="tag">Git</span>
              </div>
            </div>
            <span className="proj-status">Academic</span>
          </div>

          <div className="proj-card ai">
            <div className="proj-info">
              <div className="proj-cat">AI Exploration</div>
              <div className="proj-name">AI Prompt Engineering</div>
              <p className="proj-desc">Explored ChatGPT, prompt chaining, content pipelines, and automated workflows using Google Colab and Copilot.</p>
              <div className="proj-tags">
                <span className="tag">ChatGPT</span>
                <span className="tag">Prompt Eng.</span>
                <span className="tag">Google Colab</span>
              </div>
            </div>
            <span className="proj-status">Self-Initiated</span>
          </div>
        </div>
      </section>

      <section id="skills" className="section-light">
        <div className="section-header">
          <span className="section-tag">// expertise</span>
          <h2 className="section-title">Skills &amp; Tools</h2>
          <p className="section-sub">Technologies I actively work with, grouped by domain.</p>
        </div>
        <div className="skills-grid">
          {[
            {title:'Web Dev',icon:'🌐',skills:['Python','HTML5','CSS3','Bootstrap','JavaScript']},
            {title:'Dev Tools',icon:'🛠',skills:['Git','GitHub','GitHub Copilot','VS Code']},
            {title:'AI &amp; Tech',icon:'🤖',skills:['ML Basics','ChatGPT','Prompt Eng.','Google Colab','Cloud']},
            {title:'Design',icon:'🎨',skills:['Canva','Photoshop','MS Designer']},
          ].map((cat,i)=>(
            <div key={i} className="skill-card">
              <div className="skill-header">
                <span className="skill-icon">{cat.icon}</span>
                <h3>{cat.title}</h3>
              </div>
              <div className="skill-items">
                {cat.skills.map(s=><span key={s} className="sk">{s}</span>)}
              </div>
            </div>
          ))}
          <div className="skill-card" style={{gridColumn:'1/-1'}}>
            <div className="skill-header">
              <span className="skill-icon">💡</span>
              <h3>Soft Skills</h3>
            </div>
            <div className="skill-items">
              {['Communication','Teamwork','Problem Solving','Logical Thinking','OS Setup','Troubleshooting'].map(s=><span key={s} className="sk">{s}</span>)}
            </div>
          </div>
        </div>
      </section>

      <section id="hire">
        <div className="hire-inner">
          <div className="hire-text">
            <span className="section-tag">// let'''s work together</span>
            <h2 className="section-title">Open to Opportunities</h2>
            <p className="section-sub">Actively seeking my first industry internship. Ready to learn, contribute, and grow.</p>
            <div className="avail"><span className="avail-dot"></span> Open to Internships &amp; Freelance</div>
            <div className="services">
              {['Web Development','Python Scripting','AI-Assisted Projects','Graphic Design','Technical Support'].map(s=>(
                <div key={s} className="svc"><span className="svc-dot"></span>{s}</div>
              ))}
            </div>
            <a href="#contact" className="btn btn-primary">Get In Touch →</a>
          </div>
          <div className="hire-card">
            <h3>Ready to Start?</h3>
            <p>Contact me for internship opportunities, freelance projects, or just to chat about tech.</p>
            <a href="https://linkedin.com/in/muhammad-awais-0287743a9" target="_blank" className="btn btn-primary">Connect on LinkedIn</a>
          </div>
        </div>
      </section>

      <section id="contact" className="section-light">
        <div className="section-header">
          <span className="section-tag">// reach out</span>
          <h2 className="section-title">Get In Touch</h2>
          <p className="section-sub">Feel free to reach out for opportunities or just to say hello!</p>
        </div>
        <div className="contact-grid">
          <div className="contact-info">
            <div className="contact-card">
              <span className="contact-icon">✉️</span>
              <div><div className="contact-lbl">Email</div><div className="contact-val">awaiss.dev@gmail.com</div></div>
            </div>
            <div className="contact-card">
              <span className="contact-icon">📞</span>
              <div><div className="contact-lbl">WhatsApp</div><div className="contact-val">+92 307 9838110</div></div>
            </div>
            <div className="contact-card">
              <span className="contact-icon">💼</span>
              <div><div className="contact-lbl">LinkedIn</div><a href="https://linkedin.com/in/muhammad-awais-0287743a9" target="_blank" className="contact-link">View Profile</a></div>
            </div>
            <div className="contact-card">
              <span className="contact-icon">🐙</span>
              <div><div className="contact-lbl">GitHub</div><div className="contact-val">github.com/awaiss</div></div>
            </div>
          </div>
          <form className="contact-form" onSubmit={handleContact}>
            <div className="form-row">
              <div className="fg">
                <label>Name</label>
                <input type="text" name="name" placeholder="Your name" required />
              </div>
              <div className="fg">
                <label>Email</label>
                <input type="email" name="email" placeholder="your@email.com" required />
              </div>
            </div>
            <div className="fg">
              <label>Subject</label>
              <input type="text" name="subject" placeholder="Internship, freelance project..." />
            </div>
            <div className="fg">
              <label>Message</label>
              <textarea name="message" placeholder="Tell me about your project..." required></textarea>
            </div>
            <button type="submit" className="btn btn-primary" disabled={sending}>
              {sending ? 'Sending...' : 'Send Message →'}
            </button>
            {formMsg && <div className="form-msg">{formMsg}</div>}
          </form>
        </div>
      </section>

      <footer>
        <div className="footer-logo">MA<span>.</span></div>
        <div className="footer-copy">© {new Date().getFullYear()} Muhammad Awais — Karachi, Pakistan</div>
        <div className="footer-socials">
          <a href="https://linkedin.com/in/muhammad-awais-0287743a9" target="_blank">LinkedIn</a>
          <a href="https://github.com/awaiss" target="_blank">GitHub</a>
          <a href="mailto:awaiss.dev@gmail.com">Email</a>
          <a href="#home">Top ↑</a>
        </div>
      </footer>

      {scrolled > 400 && (
        <button 
          className="btt"
          onClick={() => window.scrollTo({ top: 0, behavior: 'smooth' })}
          title="Back to top"
        >
          ↑
        </button>
      )}
    </div>
  )
}
